import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine(); // Read entire line including spaces

        // Validate user input length
        if(userInput.length() > 10) {
            System.out.println("Input exceeds buffer size limit.");
            return;
        }

        char[] buffer = new char[10]; // Buffer with fixed size
        userInput.getChars(0, Math.min(userInput.length(), buffer.length), buffer, 0); // Copy limited portion of user input into the buffer

        System.out.println("User input: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
